1	export type Cell = [number, number];
2	
3	const cellsEqual = (a: Cell, b: Cell): boolean => a[0] === b[0] && a[1] === b[1];
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
17	  neighborsOf(cell).filter((neighbor) => liveCells.some((live) => cellsEqual(live, neighbor))).length;
18	
19	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
20	  liveCells.some((live) => cellsEqual(live, cell));
21	
22	const uniqueCells = (cells: Cell[]): Cell[] =>
23	  cells.filter((cell, index) => cells.findIndex((other) => cellsEqual(other, cell)) === index);
24	
25	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
26	  const candidates = uniqueCells([...liveCells, ...liveCells.flatMap(neighborsOf)]);
27	  return candidates.filter((cell) => {
28	    const liveNeighborCount = countLiveNeighbors(cell, liveCells);
29	    if (isLive(cell, liveCells)) return liveNeighborCount === 2 || liveNeighborCount === 3;
30	    return liveNeighborCount === 3;
31	  });
32	};
